#include "jayess_runtime.h"

#include <curl/curl.h>

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

typedef struct jayess_curl_easy_handle {
    CURL *easy;
    struct curl_slist *request_headers;
    unsigned char *body_data;
    size_t body_length;
    char *output_path;
} jayess_curl_easy_handle;

typedef struct jayess_curl_buffer {
    unsigned char *data;
    size_t length;
    size_t capacity;
    FILE *file;
} jayess_curl_buffer;

typedef struct jayess_curl_multi_handle {
    CURLM *multi;
    jayess_curl_easy_handle **handles;
    int count;
    int capacity;
} jayess_curl_multi_handle;

typedef struct jayess_curl_multi_transfer {
    jayess_curl_easy_handle *handle;
    jayess_curl_buffer body;
    jayess_curl_buffer headers;
    CURLcode result_code;
} jayess_curl_multi_transfer;

typedef struct jayess_curl_stream_state {
    jayess_value *callback;
    jayess_curl_buffer headers;
    size_t chunk_count;
} jayess_curl_stream_state;

static int jayess_curl_global_ready = 0;

static void jayess_curl_free_easy(jayess_curl_easy_handle *handle) {
    if (handle == NULL) {
        return;
    }
    if (handle->request_headers != NULL) {
        curl_slist_free_all(handle->request_headers);
        handle->request_headers = NULL;
    }
    if (handle->body_data != NULL) {
        jayess_bytes_free(handle->body_data);
        handle->body_data = NULL;
    }
    handle->body_length = 0;
    if (handle->output_path != NULL) {
        jayess_string_free(handle->output_path);
        handle->output_path = NULL;
    }
    if (handle->easy != NULL) {
        curl_easy_cleanup(handle->easy);
        handle->easy = NULL;
    }
}

static void jayess_curl_finalize(void *raw) {
    jayess_curl_easy_handle *handle = (jayess_curl_easy_handle *)raw;
    if (handle == NULL) {
        return;
    }
    jayess_curl_free_easy(handle);
    free(handle);
}

static int jayess_curl_ensure_global(void) {
    if (jayess_curl_global_ready) {
        return 1;
    }
    if (curl_global_init(CURL_GLOBAL_DEFAULT) != CURLE_OK) {
        jayess_throw_named_error("CurlError", "failed to initialize libcurl");
        return 0;
    }
    jayess_curl_global_ready = 1;
    return 1;
}

static int jayess_curl_equal_name(const char *left, const char *right) {
    size_t i = 0;
    if (left == NULL || right == NULL) {
        return 0;
    }
    while (left[i] != '\0' && right[i] != '\0') {
        char a = left[i];
        char b = right[i];
        if (a >= 'A' && a <= 'Z') {
            a = (char)(a - 'A' + 'a');
        }
        if (b >= 'A' && b <= 'Z') {
            b = (char)(b - 'A' + 'a');
        }
        if (a != b) {
            return 0;
        }
        i++;
    }
    return left[i] == '\0' && right[i] == '\0';
}

static unsigned char *jayess_curl_bytes_copy(jayess_value *value, const char *context, size_t *length_out) {
    const char *text = jayess_value_as_string(value);
    if (text != NULL) {
        char *copy = jayess_value_to_string_copy(value);
        if (copy == NULL) {
            jayess_throw_type_error(context);
            return NULL;
        }
        if (length_out != NULL) {
            *length_out = strlen(copy);
        }
        return (unsigned char *)copy;
    }
    return jayess_expect_bytes_copy(value, length_out, context);
}

static char *jayess_curl_optional_string(jayess_object *options, const char *key) {
    jayess_value *value = jayess_object_get(options, key);
    if (value == NULL || jayess_value_is_nullish(value)) {
        return NULL;
    }
    return jayess_value_to_string_copy(value);
}

static int jayess_curl_optional_bool(jayess_object *options, const char *key, int fallback) {
    jayess_value *value = jayess_object_get(options, key);
    if (value == NULL || jayess_value_is_nullish(value)) {
        return fallback;
    }
    return jayess_value_as_bool(value);
}

static long jayess_curl_optional_long(jayess_object *options, const char *key, long fallback) {
    jayess_value *value = jayess_object_get(options, key);
    if (value == NULL || jayess_value_is_nullish(value)) {
        return fallback;
    }
    return (long)jayess_value_to_number(value);
}

static int jayess_curl_append_buffer(jayess_curl_buffer *buffer, const unsigned char *data, size_t length) {
    size_t needed = 0;
    unsigned char *grown = NULL;
    if (buffer->file != NULL) {
        return fwrite(data, 1, length, buffer->file) == length;
    }
    needed = buffer->length + length + 1;
    if (needed > buffer->capacity) {
        size_t capacity = buffer->capacity == 0 ? 256 : buffer->capacity;
        while (capacity < needed) {
            capacity *= 2;
        }
        grown = (unsigned char *)realloc(buffer->data, capacity);
        if (grown == NULL) {
            return 0;
        }
        buffer->data = grown;
        buffer->capacity = capacity;
    }
    memcpy(buffer->data + buffer->length, data, length);
    buffer->length += length;
    buffer->data[buffer->length] = '\0';
    return 1;
}

static size_t jayess_curl_write_callback(char *ptr, size_t size, size_t nmemb, void *userdata) {
    size_t length = size * nmemb;
    jayess_curl_buffer *buffer = (jayess_curl_buffer *)userdata;
    if (!jayess_curl_append_buffer(buffer, (const unsigned char *)ptr, length)) {
        return 0;
    }
    return length;
}

static size_t jayess_curl_header_callback(char *ptr, size_t size, size_t nmemb, void *userdata) {
    return jayess_curl_write_callback(ptr, size, nmemb, userdata);
}

static size_t jayess_curl_stream_write_callback(char *ptr, size_t size, size_t nmemb, void *userdata) {
    size_t length = size * nmemb;
    jayess_curl_stream_state *state = (jayess_curl_stream_state *)userdata;
    char *chunk = NULL;
    if (state == NULL) {
        return 0;
    }
    chunk = (char *)malloc(length + 1);
    if (chunk == NULL) {
        jayess_throw_named_error("CurlError", "failed to allocate curl stream chunk");
        return 0;
    }
    memcpy(chunk, ptr, length);
    chunk[length] = '\0';
    state->chunk_count++;
    jayess_call_function(state->callback, jayess_value_from_string(chunk));
    free(chunk);
    if (jayess_has_exception()) {
        return 0;
    }
    return length;
}

static int jayess_curl_set_headers(jayess_curl_easy_handle *handle, jayess_object *options) {
    jayess_value *headers_value = jayess_object_get(options, "headers");
    int index = 0;
    if (headers_value == NULL || jayess_value_is_nullish(headers_value)) {
        return 1;
    }
    {
        jayess_array *headers = jayess_expect_array(headers_value, "jayess_curl_configure_native");
        if (jayess_has_exception()) {
            return 0;
        }
        for (index = 0; index < jayess_array_length(headers); index++) {
            const char *header_text = jayess_expect_string(jayess_array_get(headers, index), "jayess_curl_configure_native");
            struct curl_slist *next = NULL;
            if (jayess_has_exception()) {
                return 0;
            }
            next = curl_slist_append(handle->request_headers, header_text);
            if (next == NULL) {
                jayess_throw_named_error("CurlError", "failed to allocate curl header list");
                return 0;
            }
            handle->request_headers = next;
        }
    }
    if (handle->request_headers != NULL && curl_easy_setopt(handle->easy, CURLOPT_HTTPHEADER, handle->request_headers) != CURLE_OK) {
        jayess_throw_named_error("CurlError", "failed to configure curl request headers");
        return 0;
    }
    return 1;
}

static int jayess_curl_apply_method(jayess_curl_easy_handle *handle, const char *method) {
    if (curl_easy_setopt(handle->easy, CURLOPT_HTTPGET, 0L) != CURLE_OK ||
        curl_easy_setopt(handle->easy, CURLOPT_POST, 0L) != CURLE_OK ||
        curl_easy_setopt(handle->easy, CURLOPT_UPLOAD, 0L) != CURLE_OK ||
        curl_easy_setopt(handle->easy, CURLOPT_NOBODY, 0L) != CURLE_OK ||
        curl_easy_setopt(handle->easy, CURLOPT_CUSTOMREQUEST, NULL) != CURLE_OK) {
        jayess_throw_named_error("CurlError", "failed to reset curl request method");
        return 0;
    }
    if (method == NULL || jayess_curl_equal_name(method, "GET")) {
        if (curl_easy_setopt(handle->easy, CURLOPT_HTTPGET, 1L) != CURLE_OK) {
            jayess_throw_named_error("CurlError", "failed to configure curl GET request");
            return 0;
        }
        return 1;
    }
    if (jayess_curl_equal_name(method, "POST")) {
        if (curl_easy_setopt(handle->easy, CURLOPT_POST, 1L) != CURLE_OK) {
            jayess_throw_named_error("CurlError", "failed to configure curl POST request");
            return 0;
        }
        return 1;
    }
    if (jayess_curl_equal_name(method, "HEAD")) {
        if (curl_easy_setopt(handle->easy, CURLOPT_NOBODY, 1L) != CURLE_OK) {
            jayess_throw_named_error("CurlError", "failed to configure curl HEAD request");
            return 0;
        }
        return 1;
    }
    if (curl_easy_setopt(handle->easy, CURLOPT_CUSTOMREQUEST, method) != CURLE_OK) {
        jayess_throw_named_error("CurlError", "failed to configure curl request method");
        return 0;
    }
    return 1;
}

static jayess_value *jayess_curl_headers_to_value(const unsigned char *data, size_t length) {
    jayess_array *headers = jayess_array_new();
    size_t start = 0;
    size_t index = 0;
    while (index < length) {
        size_t line_end = index;
        while (line_end < length && data[line_end] != '\n') {
            line_end++;
        }
        if (line_end > start) {
            size_t trimmed_end = line_end;
            char *line = NULL;
            while (trimmed_end > start && (data[trimmed_end - 1] == '\r' || data[trimmed_end - 1] == '\n')) {
                trimmed_end--;
            }
            if (trimmed_end > start) {
                line = (char *)malloc(trimmed_end - start + 1);
                if (line == NULL) {
                    jayess_throw_named_error("CurlError", "failed to allocate curl response header");
                    return jayess_value_undefined();
                }
                memcpy(line, data + start, trimmed_end - start);
                line[trimmed_end - start] = '\0';
                jayess_array_push_value(headers, jayess_value_from_string(line));
                free(line);
                if (jayess_has_exception()) {
                    return jayess_value_undefined();
                }
            }
        }
        index = line_end + 1;
        start = index;
    }
    return jayess_value_from_array(headers);
}

static void jayess_curl_multi_finalize(void *raw) {
    jayess_curl_multi_handle *multi = (jayess_curl_multi_handle *)raw;
    int index = 0;
    if (multi == NULL) {
        return;
    }
    if (multi->multi != NULL) {
        for (index = 0; index < multi->count; index++) {
            if (multi->handles[index] != NULL && multi->handles[index]->easy != NULL) {
                curl_multi_remove_handle(multi->multi, multi->handles[index]->easy);
            }
        }
        curl_multi_cleanup(multi->multi);
        multi->multi = NULL;
    }
    free(multi->handles);
    free(multi);
}

static int jayess_curl_multi_append_handle(jayess_curl_multi_handle *multi, jayess_curl_easy_handle *handle) {
    jayess_curl_easy_handle **grown = NULL;
    int index = 0;
    if (multi == NULL || handle == NULL) {
        return 0;
    }
    for (index = 0; index < multi->count; index++) {
        if (multi->handles[index] == handle) {
            jayess_throw_named_error("CurlError", "curl easy handle already added to multi handle");
            return 0;
        }
    }
    if (multi->count == multi->capacity) {
        int next_capacity = multi->capacity == 0 ? 4 : multi->capacity * 2;
        grown = (jayess_curl_easy_handle **)realloc(multi->handles, (size_t)next_capacity * sizeof(jayess_curl_easy_handle *));
        if (grown == NULL) {
            jayess_throw_named_error("CurlError", "failed to grow curl multi handle list");
            return 0;
        }
        multi->handles = grown;
        multi->capacity = next_capacity;
    }
    multi->handles[multi->count++] = handle;
    return 1;
}

static void jayess_curl_multi_transfer_free(jayess_curl_multi_transfer *transfer) {
    if (transfer == NULL) {
        return;
    }
    if (transfer->body.file != NULL) {
        fclose(transfer->body.file);
        transfer->body.file = NULL;
    }
    free(transfer->body.data);
    transfer->body.data = NULL;
    transfer->body.length = 0;
    transfer->body.capacity = 0;
    free(transfer->headers.data);
    transfer->headers.data = NULL;
    transfer->headers.length = 0;
    transfer->headers.capacity = 0;
}

jayess_value *jayess_curl_create_easy_native(void) {
    jayess_curl_easy_handle *handle = NULL;
    if (!jayess_curl_ensure_global()) {
        return jayess_value_undefined();
    }
    handle = (jayess_curl_easy_handle *)calloc(1, sizeof(jayess_curl_easy_handle));
    if (handle == NULL) {
        jayess_throw_named_error("CurlError", "failed to allocate curl easy handle");
        return jayess_value_undefined();
    }
    handle->easy = curl_easy_init();
    if (handle->easy == NULL) {
        free(handle);
        jayess_throw_named_error("CurlError", "failed to create curl easy handle");
        return jayess_value_undefined();
    }
    curl_easy_setopt(handle->easy, CURLOPT_NOSIGNAL, 1L);
    curl_easy_setopt(handle->easy, CURLOPT_ACCEPT_ENCODING, "");
    curl_easy_setopt(handle->easy, CURLOPT_USERAGENT, "jayess-curl/0");
    return jayess_value_from_managed_native_handle("CurlEasy", handle, jayess_curl_finalize);
}

jayess_value *jayess_curl_configure_native(jayess_value *handle_value, jayess_value *options_value) {
    jayess_curl_easy_handle *handle = (jayess_curl_easy_handle *)jayess_expect_native_handle(handle_value, "CurlEasy", "jayess_curl_configure_native");
    jayess_object *options = jayess_expect_object(options_value, "jayess_curl_configure_native");
    jayess_value *url_value = NULL;
    const char *url = NULL;
    char *method = NULL;
    char *proxy = NULL;
    char *cookie = NULL;
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }

    if (handle->request_headers != NULL) {
        curl_slist_free_all(handle->request_headers);
        handle->request_headers = NULL;
    }
    if (handle->body_data != NULL) {
        jayess_bytes_free(handle->body_data);
        handle->body_data = NULL;
    }
    handle->body_length = 0;
    if (handle->output_path != NULL) {
        jayess_string_free(handle->output_path);
        handle->output_path = NULL;
    }

    url_value = jayess_object_get(options, "url");
    url = jayess_expect_string(url_value, "jayess_curl_configure_native");
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    if (curl_easy_setopt(handle->easy, CURLOPT_URL, url) != CURLE_OK) {
        jayess_throw_named_error("CurlError", "failed to configure curl URL");
        return jayess_value_undefined();
    }

    method = jayess_curl_optional_string(options, "method");
    if (jayess_has_exception()) {
        jayess_string_free(method);
        return jayess_value_undefined();
    }
    if (!jayess_curl_apply_method(handle, method)) {
        jayess_string_free(method);
        return jayess_value_undefined();
    }

    if (!jayess_curl_set_headers(handle, options)) {
        jayess_string_free(method);
        return jayess_value_undefined();
    }

    {
        jayess_value *body_value = jayess_object_get(options, "body");
        if (body_value != NULL && !jayess_value_is_nullish(body_value)) {
            handle->body_data = jayess_curl_bytes_copy(body_value, "jayess_curl_configure_native", &handle->body_length);
            if (jayess_has_exception()) {
                jayess_string_free(method);
                return jayess_value_undefined();
            }
            if (curl_easy_setopt(handle->easy, CURLOPT_POSTFIELDS, handle->body_data) != CURLE_OK ||
                curl_easy_setopt(handle->easy, CURLOPT_POSTFIELDSIZE, (long)handle->body_length) != CURLE_OK) {
                jayess_string_free(method);
                jayess_throw_named_error("CurlError", "failed to configure curl request body");
                return jayess_value_undefined();
            }
            if (method == NULL || jayess_curl_equal_name(method, "GET")) {
                if (curl_easy_setopt(handle->easy, CURLOPT_POST, 1L) != CURLE_OK) {
                    jayess_string_free(method);
                    jayess_throw_named_error("CurlError", "failed to switch curl request to POST");
                    return jayess_value_undefined();
                }
            }
        } else {
            curl_easy_setopt(handle->easy, CURLOPT_POSTFIELDS, NULL);
            curl_easy_setopt(handle->easy, CURLOPT_POSTFIELDSIZE, 0L);
        }
    }

    if (curl_easy_setopt(handle->easy, CURLOPT_FOLLOWLOCATION, (long)jayess_curl_optional_bool(options, "followRedirects", 0)) != CURLE_OK) {
        jayess_string_free(method);
        jayess_throw_named_error("CurlError", "failed to configure curl redirect policy");
        return jayess_value_undefined();
    }
    if (curl_easy_setopt(handle->easy, CURLOPT_TIMEOUT_MS, jayess_curl_optional_long(options, "timeoutMs", 0L)) != CURLE_OK) {
        jayess_string_free(method);
        jayess_throw_named_error("CurlError", "failed to configure curl timeout");
        return jayess_value_undefined();
    }
    if (jayess_curl_optional_bool(options, "insecure", 0)) {
        curl_easy_setopt(handle->easy, CURLOPT_SSL_VERIFYPEER, 0L);
        curl_easy_setopt(handle->easy, CURLOPT_SSL_VERIFYHOST, 0L);
    } else {
        curl_easy_setopt(handle->easy, CURLOPT_SSL_VERIFYPEER, 1L);
        curl_easy_setopt(handle->easy, CURLOPT_SSL_VERIFYHOST, 2L);
    }

    proxy = jayess_curl_optional_string(options, "proxy");
    if (jayess_has_exception()) {
        jayess_string_free(method);
        jayess_string_free(proxy);
        return jayess_value_undefined();
    }
    if (curl_easy_setopt(handle->easy, CURLOPT_PROXY, proxy != NULL ? proxy : NULL) != CURLE_OK) {
        jayess_string_free(method);
        jayess_string_free(proxy);
        jayess_throw_named_error("CurlError", "failed to configure curl proxy");
        return jayess_value_undefined();
    }
    jayess_string_free(proxy);

    cookie = jayess_curl_optional_string(options, "cookie");
    if (jayess_has_exception()) {
        jayess_string_free(method);
        jayess_string_free(cookie);
        return jayess_value_undefined();
    }
    if (curl_easy_setopt(handle->easy, CURLOPT_COOKIE, cookie != NULL ? cookie : NULL) != CURLE_OK) {
        jayess_string_free(method);
        jayess_string_free(cookie);
        jayess_throw_named_error("CurlError", "failed to configure curl cookies");
        return jayess_value_undefined();
    }
    jayess_string_free(cookie);

    handle->output_path = jayess_curl_optional_string(options, "outputPath");
    if (jayess_has_exception()) {
        jayess_string_free(method);
        return jayess_value_undefined();
    }

    jayess_string_free(method);
    return handle_value;
}

jayess_value *jayess_curl_perform_native(jayess_value *handle_value) {
    jayess_curl_easy_handle *handle = (jayess_curl_easy_handle *)jayess_expect_native_handle(handle_value, "CurlEasy", "jayess_curl_perform_native");
    jayess_curl_buffer body = {0};
    jayess_curl_buffer headers = {0};
    long status = 0;
    CURLcode code;
    jayess_object *result = NULL;
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    if (handle->output_path != NULL) {
        body.file = fopen(handle->output_path, "wb");
        if (body.file == NULL) {
            jayess_throw_named_error("CurlError", "failed to open curl output file");
            return jayess_value_undefined();
        }
    }
    if (curl_easy_setopt(handle->easy, CURLOPT_WRITEFUNCTION, jayess_curl_write_callback) != CURLE_OK ||
        curl_easy_setopt(handle->easy, CURLOPT_WRITEDATA, &body) != CURLE_OK ||
        curl_easy_setopt(handle->easy, CURLOPT_HEADERFUNCTION, jayess_curl_header_callback) != CURLE_OK ||
        curl_easy_setopt(handle->easy, CURLOPT_HEADERDATA, &headers) != CURLE_OK) {
        if (body.file != NULL) {
            fclose(body.file);
        }
        jayess_throw_named_error("CurlError", "failed to configure curl response handlers");
        free(body.data);
        free(headers.data);
        return jayess_value_undefined();
    }
    code = curl_easy_perform(handle->easy);
    if (body.file != NULL) {
        fclose(body.file);
    }
    if (code != CURLE_OK) {
        free(body.data);
        free(headers.data);
        jayess_throw_named_error("CurlError", curl_easy_strerror(code));
        return jayess_value_undefined();
    }
    if (curl_easy_getinfo(handle->easy, CURLINFO_RESPONSE_CODE, &status) != CURLE_OK) {
        free(body.data);
        free(headers.data);
        jayess_throw_named_error("CurlError", "failed to read curl response status");
        return jayess_value_undefined();
    }

    result = jayess_object_new();
    jayess_object_set_value(result, "status", jayess_value_from_number((double)status));
    jayess_object_set_value(result, "headers", jayess_curl_headers_to_value(headers.data, headers.length));
    if (handle->output_path != NULL) {
        jayess_object_set_value(result, "body", jayess_value_undefined());
        jayess_object_set_value(result, "path", jayess_value_from_string(handle->output_path));
    } else {
        const char *body_text = body.data != NULL ? (const char *)body.data : "";
        jayess_object_set_value(result, "body", jayess_value_from_string(body_text));
        jayess_object_set_value(result, "path", jayess_value_undefined());
    }

    free(body.data);
    free(headers.data);
    return jayess_value_from_object(result);
}

jayess_value *jayess_curl_cleanup_native(jayess_value *handle_value) {
    return jayess_value_from_bool(jayess_value_close_native_handle(handle_value));
}

jayess_value *jayess_curl_perform_stream_native(jayess_value *handle_value, jayess_value *callback_value) {
    jayess_curl_easy_handle *handle = (jayess_curl_easy_handle *)jayess_expect_native_handle(handle_value, "CurlEasy", "jayess_curl_perform_stream_native");
    jayess_curl_stream_state state = {0};
    long status = 0;
    CURLcode code;
    jayess_object *result = NULL;
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    if (callback_value == NULL || jayess_value_function_ptr(callback_value) == NULL) {
        jayess_throw_not_function();
        return jayess_value_undefined();
    }
    if (handle->output_path != NULL) {
        jayess_throw_named_error("CurlError", "curl streaming does not support outputPath");
        return jayess_value_undefined();
    }
    state.callback = callback_value;
    if (curl_easy_setopt(handle->easy, CURLOPT_WRITEFUNCTION, jayess_curl_stream_write_callback) != CURLE_OK ||
        curl_easy_setopt(handle->easy, CURLOPT_WRITEDATA, &state) != CURLE_OK ||
        curl_easy_setopt(handle->easy, CURLOPT_HEADERFUNCTION, jayess_curl_header_callback) != CURLE_OK ||
        curl_easy_setopt(handle->easy, CURLOPT_HEADERDATA, &state.headers) != CURLE_OK) {
        free(state.headers.data);
        jayess_throw_named_error("CurlError", "failed to configure curl streaming response handlers");
        return jayess_value_undefined();
    }
    code = curl_easy_perform(handle->easy);
    if (code != CURLE_OK) {
        free(state.headers.data);
        if (jayess_has_exception()) {
            return jayess_value_undefined();
        }
        jayess_throw_named_error("CurlError", curl_easy_strerror(code));
        return jayess_value_undefined();
    }
    if (curl_easy_getinfo(handle->easy, CURLINFO_RESPONSE_CODE, &status) != CURLE_OK) {
        free(state.headers.data);
        jayess_throw_named_error("CurlError", "failed to read curl response status");
        return jayess_value_undefined();
    }
    result = jayess_object_new();
    jayess_object_set_value(result, "status", jayess_value_from_number((double)status));
    jayess_object_set_value(result, "headers", jayess_curl_headers_to_value(state.headers.data, state.headers.length));
    jayess_object_set_value(result, "body", jayess_value_undefined());
    jayess_object_set_value(result, "path", jayess_value_undefined());
    jayess_object_set_value(result, "chunks", jayess_value_from_number((double)state.chunk_count));
    free(state.headers.data);
    return jayess_value_from_object(result);
}

jayess_value *jayess_curl_create_multi_native(void) {
    jayess_curl_multi_handle *multi = NULL;
    if (!jayess_curl_ensure_global()) {
        return jayess_value_undefined();
    }
    multi = (jayess_curl_multi_handle *)calloc(1, sizeof(jayess_curl_multi_handle));
    if (multi == NULL) {
        jayess_throw_named_error("CurlError", "failed to allocate curl multi handle");
        return jayess_value_undefined();
    }
    multi->multi = curl_multi_init();
    if (multi->multi == NULL) {
        free(multi);
        jayess_throw_named_error("CurlError", "failed to create curl multi handle");
        return jayess_value_undefined();
    }
    return jayess_value_from_managed_native_handle("CurlMulti", multi, jayess_curl_multi_finalize);
}

jayess_value *jayess_curl_add_handle_native(jayess_value *multi_value, jayess_value *handle_value) {
    jayess_curl_multi_handle *multi = (jayess_curl_multi_handle *)jayess_expect_native_handle(multi_value, "CurlMulti", "jayess_curl_add_handle_native");
    jayess_curl_easy_handle *handle = (jayess_curl_easy_handle *)jayess_expect_native_handle(handle_value, "CurlEasy", "jayess_curl_add_handle_native");
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    if (!jayess_curl_multi_append_handle(multi, handle)) {
        return jayess_value_undefined();
    }
    if (curl_multi_add_handle(multi->multi, handle->easy) != CURLM_OK) {
        multi->count--;
        jayess_throw_named_error("CurlError", "failed to add curl easy handle to multi handle");
        return jayess_value_undefined();
    }
    return multi_value;
}

jayess_value *jayess_curl_perform_multi_native(jayess_value *multi_value) {
    jayess_curl_multi_handle *multi = (jayess_curl_multi_handle *)jayess_expect_native_handle(multi_value, "CurlMulti", "jayess_curl_perform_multi_native");
    jayess_curl_multi_transfer *transfers = NULL;
    jayess_array *results = NULL;
    CURLMcode multi_code = CURLM_OK;
    int running = 0;
    int index = 0;
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    results = jayess_array_new();
    if (multi->count == 0) {
        return jayess_value_from_array(results);
    }
    transfers = (jayess_curl_multi_transfer *)calloc((size_t)multi->count, sizeof(jayess_curl_multi_transfer));
    if (transfers == NULL) {
        jayess_throw_named_error("CurlError", "failed to allocate curl multi transfer state");
        return jayess_value_undefined();
    }
    for (index = 0; index < multi->count; index++) {
        transfers[index].handle = multi->handles[index];
        transfers[index].result_code = CURLE_OK;
        if (multi->handles[index]->output_path != NULL) {
            transfers[index].body.file = fopen(multi->handles[index]->output_path, "wb");
            if (transfers[index].body.file == NULL) {
                jayess_throw_named_error("CurlError", "failed to open curl output file");
                goto cleanup;
            }
        }
        if (curl_easy_setopt(multi->handles[index]->easy, CURLOPT_WRITEFUNCTION, jayess_curl_write_callback) != CURLE_OK ||
            curl_easy_setopt(multi->handles[index]->easy, CURLOPT_WRITEDATA, &transfers[index].body) != CURLE_OK ||
            curl_easy_setopt(multi->handles[index]->easy, CURLOPT_HEADERFUNCTION, jayess_curl_header_callback) != CURLE_OK ||
            curl_easy_setopt(multi->handles[index]->easy, CURLOPT_HEADERDATA, &transfers[index].headers) != CURLE_OK ||
            curl_easy_setopt(multi->handles[index]->easy, CURLOPT_PRIVATE, &transfers[index]) != CURLE_OK) {
            jayess_throw_named_error("CurlError", "failed to configure curl multi response handlers");
            goto cleanup;
        }
    }
    multi_code = curl_multi_perform(multi->multi, &running);
    if (multi_code != CURLM_OK) {
        jayess_throw_named_error("CurlError", curl_multi_strerror(multi_code));
        goto cleanup;
    }
    while (running > 0) {
        int numfds = 0;
        multi_code = curl_multi_poll(multi->multi, NULL, 0, 1000, &numfds);
        if (multi_code != CURLM_OK) {
            jayess_throw_named_error("CurlError", curl_multi_strerror(multi_code));
            goto cleanup;
        }
        multi_code = curl_multi_perform(multi->multi, &running);
        if (multi_code != CURLM_OK) {
            jayess_throw_named_error("CurlError", curl_multi_strerror(multi_code));
            goto cleanup;
        }
    }
    for (;;) {
        int msgs_left = 0;
        CURLMsg *message = curl_multi_info_read(multi->multi, &msgs_left);
        if (message == NULL) {
            break;
        }
        if (message->msg == CURLMSG_DONE) {
            jayess_curl_multi_transfer *transfer = NULL;
            if (curl_easy_getinfo(message->easy_handle, CURLINFO_PRIVATE, &transfer) == CURLE_OK && transfer != NULL) {
                transfer->result_code = message->data.result;
            }
        }
    }
    for (index = 0; index < multi->count; index++) {
        jayess_object *result = NULL;
        long status = 0;
        if (transfers[index].result_code != CURLE_OK) {
            jayess_throw_named_error("CurlError", curl_easy_strerror(transfers[index].result_code));
            goto cleanup;
        }
        if (curl_easy_getinfo(multi->handles[index]->easy, CURLINFO_RESPONSE_CODE, &status) != CURLE_OK) {
            jayess_throw_named_error("CurlError", "failed to read curl multi response status");
            goto cleanup;
        }
        result = jayess_object_new();
        jayess_object_set_value(result, "status", jayess_value_from_number((double)status));
        jayess_object_set_value(result, "headers", jayess_curl_headers_to_value(transfers[index].headers.data, transfers[index].headers.length));
        if (multi->handles[index]->output_path != NULL) {
            jayess_object_set_value(result, "body", jayess_value_undefined());
            jayess_object_set_value(result, "path", jayess_value_from_string(multi->handles[index]->output_path));
        } else {
            const char *body_text = transfers[index].body.data != NULL ? (const char *)transfers[index].body.data : "";
            jayess_object_set_value(result, "body", jayess_value_from_string(body_text));
            jayess_object_set_value(result, "path", jayess_value_undefined());
        }
        jayess_array_push_value(results, jayess_value_from_object(result));
    }

cleanup:
    for (index = 0; index < multi->count; index++) {
        if (multi->handles[index] != NULL && multi->handles[index]->easy != NULL) {
            curl_multi_remove_handle(multi->multi, multi->handles[index]->easy);
            curl_easy_setopt(multi->handles[index]->easy, CURLOPT_PRIVATE, NULL);
        }
        if (transfers != NULL) {
            jayess_curl_multi_transfer_free(&transfers[index]);
        }
    }
    free(transfers);
    multi->count = 0;
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    return jayess_value_from_array(results);
}

jayess_value *jayess_curl_cleanup_multi_native(jayess_value *multi_value) {
    return jayess_value_from_bool(jayess_value_close_native_handle(multi_value));
}
